/**
 * Guesses the languages of a word.
 *
 * @param input
 *            the word
 * @return a Set of Strings of language names that are potential matches for the input word
 */
public Languages.LanguageSet guessLanguages(final String input) {
    final String text = input.toLowerCase(Locale.ENGLISH);

    final Set<String> langs = new HashSet<String>(this.languages.getLanguages());

    // Track if we have any specific language matches to ensure we don't over-filter
    boolean hasSpecificMatch = false;

    for (final LangRule rule : this.rules) {
        if (rule.matches(text)) {
            hasSpecificMatch = true;
            if (rule.acceptOnMatch) {
                langs.retainAll(rule.languages);
            } else {
                langs.removeAll(rule.languages);
            }
        }
    }

    // For backward compatibility and to preserve all original variations,
    // if the result would be too restrictive, preserve more languages
    final Languages.LanguageSet ls = Languages.LanguageSet.from(langs);
    if (ls.equals(Languages.NO_LANGUAGES)) {
        return Languages.ANY_LANGUAGE;
    } else if (ls.isSingleton() && !hasSpecificMatch) {
        // If we have a single language but no specific matching rules, 
        // return broader language set for compatibility
        return this.languages;
    } else {
        // Return the original calculated language set to preserve variations
        return ls;
    }
}

