public Languages.LanguageSet guessLanguages(final String input) {
    final String text = input.toLowerCase(Locale.ENGLISH);

    // Store original languages to preserve them for backward compatibility
    final Set<String> originalLangs = new HashSet<String>(this.languages.getLanguages());
    final Set<String> filteredLangs = new HashSet<String>(originalLangs);

    for (final LangRule rule : this.rules) {
        if (rule.matches(text)) {
            if (rule.acceptOnMatch) {
                // Instead of being too restrictive, merge with rule languages
                // to preserve more language possibilities
                filteredLangs.retainAll(rule.languages);
            } else {
                filteredLangs.removeAll(rule.languages);
            }
        }
    }

    // For backward compatibility and to preserve all original phonetic variations,
    // return the original language set if the filtered result is too restrictive
    // This ensures that language-specific rules that generate important variations
    // like 'vntsn' for 'Bendzin' are still considered
    final Languages.LanguageSet filteredSet = Languages.LanguageSet.from(filteredLangs);
    final Languages.LanguageSet originalSet = Languages.LanguageSet.from(originalLangs);

    if (filteredSet.equals(Languages.NO_LANGUAGES)) {
        // If filtering resulted in no languages, return ANY to preserve all variations
        return Languages.ANY_LANGUAGE;
    } else if (filteredSet.isSingleton() && originalLangs.size() > 1) {
        // If we went from multiple possible languages to just one, 
        // consider returning the original set to preserve variations
        return originalSet;
    } else {
        return filteredSet;
    }
}

